   106→// handleLifecycleTurnStart handles turn start: captures pre-prompt state,
   107→// ensures strategy setup, initializes session.
   108→func handleLifecycleTurnStart(ag agent.Agent, event *agent.Event) error {
   109→	logCtx := logging.WithAgent(logging.WithComponent(context.Background(), "lifecycle"), ag.Name())
   110→	logging.Info(logCtx, "turn-start",
   111→		slog.String("event", event.Type.String()),
   112→		slog.String("session_id", event.SessionID),
   113→		slog.String("session_ref", event.SessionRef),
   114→	)
   115→
   116→	sessionID := event.SessionID
   117→	if sessionID == "" {
   118→		return fmt.Errorf("no session_id in %s event", event.Type)
   119→	}
   120→
   121→	// Capture pre-prompt state (including transcript position via TranscriptAnalyzer)
   122→	if err := CapturePrePromptState(ag, sessionID, event.SessionRef); err != nil {
   123→		return err
   124→	}
   125→
   126→	// Ensure strategy setup and initialize session
   127→	strat := GetStrategy()
   128→
   129→	if err := strat.EnsureSetup(); err != nil {
   130→		fmt.Fprintf(os.Stderr, "Warning: failed to ensure strategy setup: %v\n", err)
   131→	}
   132→
   133→	if initializer, ok := strat.(strategy.SessionInitializer); ok {
   134→		agentType := ag.Type()
   135→		if err := initializer.InitializeSession(sessionID, agentType, event.SessionRef, event.Prompt); err != nil {
   136→			fmt.Fprintf(os.Stderr, "Warning: failed to initialize session state: %v\n", err)
   137→		}
   138→	}
   139→
   140→	return nil
   141→}
   142→
   143→// handleLifecycleTurnEnd handles turn end: validates transcript, extracts metadata,
   144→// detects file changes, saves step + checkpoint, transitions phase.
   145→//
   146→//nolint:maintidx // high complexity due to sequential orchestration of 8 steps (validation, extraction, file detection, filtering, token calc, step save, phase transition, cleanup) - splitting would obscure the flow
   147→func handleLifecycleTurnEnd(ag agent.Agent, event *agent.Event) error {
   148→	logCtx := logging.WithAgent(logging.WithComponent(context.Background(), "lifecycle"), ag.Name())
   149→	logging.Info(logCtx, "turn-end",
   150→		slog.String("event", event.Type.String()),
   151→		slog.String("session_id", event.SessionID),
   152→		slog.String("session_ref", event.SessionRef),
   153→	)
   154→
   155→	sessionID := event.SessionID
   156→	if sessionID == "" {
   157→		sessionID = unknownSessionID
   158→	}
   159→
   160→	transcriptRef := event.SessionRef
   161→	if transcriptRef == "" || !fileExists(transcriptRef) {
   162→		return fmt.Errorf("transcript file not found: %s", transcriptRef)
   163→	}
   164→
   165→	// Early check: bail out quickly if the repo has no commits yet.
   166→	if repo, err := strategy.OpenRepository(); err == nil && strategy.IsEmptyRepository(repo) {
   167→		fmt.Fprintln(os.Stderr, "Entire: skipping checkpoint. Will activate after first commit.")
   168→		return NewSilentError(strategy.ErrEmptyRepository)
   169→	}
   170→
   171→	// Create session metadata directory
   172→	sessionDir := paths.SessionMetadataDirFromSessionID(sessionID)
   173→	sessionDirAbs, err := paths.AbsPath(sessionDir)
   174→	if err != nil {
   175→		sessionDirAbs = sessionDir
   176→	}
   177→	if err := os.MkdirAll(sessionDirAbs, 0o750); err != nil {
   178→		return fmt.Errorf("failed to create session directory: %w", err)
   179→	}
   180→
   181→	// If agent implements TranscriptPreparer, wait for transcript to be ready
   182→	if preparer, ok := ag.(agent.TranscriptPreparer); ok {
   183→		if err := preparer.PrepareTranscript(transcriptRef); err != nil {
   184→			fmt.Fprintf(os.Stderr, "Warning: failed to prepare transcript: %v\n", err)
   185→		}
   186→	}
   187→
   188→	// Copy transcript to session directory
   189→	transcriptData, err := ag.ReadTranscript(transcriptRef)
   190→	if err != nil {
   191→		return fmt.Errorf("failed to read transcript: %w", err)
   192→	}
   193→	logFile := filepath.Join(sessionDirAbs, paths.TranscriptFileName)
   194→	if err := os.WriteFile(logFile, transcriptData, 0o600); err != nil {
   195→		return fmt.Errorf("failed to write transcript: %w", err)
   196→	}
   197→	fmt.Fprintf(os.Stderr, "Copied transcript to: %s\n", sessionDir+"/"+paths.TranscriptFileName)
   198→
   199→	// Load pre-prompt state (captured on TurnStart)
   200→	preState, err := LoadPrePromptState(sessionID)
   201→	if err != nil {
   202→		fmt.Fprintf(os.Stderr, "Warning: failed to load pre-prompt state: %v\n", err)
   203→	}
   204→
   205→	// Determine transcript offset
   206→	transcriptOffset := resolveTranscriptOffset(preState, sessionID)
   207→
   208→	// Extract metadata via agent interface (prompts, summary, modified files)
   209→	var allPrompts []string
   210→	var summary string
   211→	var modifiedFiles []string
   212→	var newTranscriptPosition int
   213→
   214→	// Compute subagents directory for agents that support subagent extraction
   215→	subagentsDir := filepath.Join(filepath.Dir(transcriptRef), "subagents")
   216→
   217→	if analyzer, ok := ag.(agent.TranscriptAnalyzer); ok {
   218→		// Extract prompts
   219→		if prompts, promptErr := analyzer.ExtractPrompts(transcriptRef, transcriptOffset); promptErr != nil {
   220→			fmt.Fprintf(os.Stderr, "Warning: failed to extract prompts: %v\n", promptErr)
   221→		} else {
   222→			allPrompts = prompts
   223→		}
   224→
   225→		// Extract summary
   226→		if s, sumErr := analyzer.ExtractSummary(transcriptRef); sumErr != nil {
   227→			fmt.Fprintf(os.Stderr, "Warning: failed to extract summary: %v\n", sumErr)
   228→		} else {
   229→			summary = s
   230→		}
   231→
   232→		// Extract modified files - prefer SubagentAwareExtractor if available to include subagent files
   233→		if subagentExtractor, subOk := ag.(agent.SubagentAwareExtractor); subOk {
   234→			if files, fileErr := subagentExtractor.ExtractAllModifiedFiles(transcriptRef, transcriptOffset, subagentsDir); fileErr != nil {
   235→				fmt.Fprintf(os.Stderr, "Warning: failed to extract modified files (with subagents): %v\n", fileErr)
   236→			} else {
   237→				modifiedFiles = files
   238→			}
   239→			// Get position from basic analyzer
   240→			if _, pos, posErr := analyzer.ExtractModifiedFilesFromOffset(transcriptRef, transcriptOffset); posErr == nil {
   241→				newTranscriptPosition = pos
   242→			}
   243→		} else {
   244→			// Fall back to basic extraction (main transcript only)
   245→			if files, pos, fileErr := analyzer.ExtractModifiedFilesFromOffset(transcriptRef, transcriptOffset); fileErr != nil {
   246→				fmt.Fprintf(os.Stderr, "Warning: failed to extract modified files: %v\n", fileErr)
   247→			} else {
   248→				modifiedFiles = files
   249→				newTranscriptPosition = pos
   250→			}
   251→		}
   252→	}
   253→
   254→	// Write prompts file
   255→	promptFile := filepath.Join(sessionDirAbs, paths.PromptFileName)
   256→	promptContent := strings.Join(allPrompts, "\n\n---\n\n")
   257→	if err := os.WriteFile(promptFile, []byte(promptContent), 0o600); err != nil {
   258→		return fmt.Errorf("failed to write prompt file: %w", err)
   259→	}
   260→	fmt.Fprintf(os.Stderr, "Extracted %d prompt(s) to: %s\n", len(allPrompts), sessionDir+"/"+paths.PromptFileName)
   261→
   262→	// Write summary file
   263→	summaryFile := filepath.Join(sessionDirAbs, paths.SummaryFileName)
   264→	if err := os.WriteFile(summaryFile, []byte(summary), 0o600); err != nil {
   265→		return fmt.Errorf("failed to write summary file: %w", err)
   266→	}
   267→	fmt.Fprintf(os.Stderr, "Extracted summary to: %s\n", sessionDir+"/"+paths.SummaryFileName)
   268→
   269→	// Generate commit message from last prompt
   270→	lastPrompt := ""
   271→	if len(allPrompts) > 0 {
   272→		lastPrompt = allPrompts[len(allPrompts)-1]
   273→	}
   274→	commitMessage := generateCommitMessage(lastPrompt)
   275→	fmt.Fprintf(os.Stderr, "Using commit message: %s\n", commitMessage)
   276→
   277→	// Get repo root for path normalization
   278→	repoRoot, err := paths.RepoRoot()
   279→	if err != nil {
   280→		return fmt.Errorf("failed to get repo root: %w", err)
   281→	}
   282→
   283→	var preUntrackedFiles []string
   284→	if preState != nil {
   285→		fmt.Fprintf(os.Stderr, "Pre-prompt state: %d pre-existing untracked files\n", len(preState.UntrackedFiles))
   286→		preUntrackedFiles = preState.PreUntrackedFiles()
   287→	}
   288→
   289→	// Detect file changes via git status
   290→	changes, err := DetectFileChanges(preUntrackedFiles)
   291→	if err != nil {
   292→		fmt.Fprintf(os.Stderr, "Warning: failed to compute file changes: %v\n", err)
   293→	}
   294→
   295→	// Filter and normalize all paths
   296→	relModifiedFiles := FilterAndNormalizePaths(modifiedFiles, repoRoot)
   297→	var relNewFiles, relDeletedFiles []string
   298→	if changes != nil {
   299→		relNewFiles = FilterAndNormalizePaths(changes.New, repoRoot)
   300→		relDeletedFiles = FilterAndNormalizePaths(changes.Deleted, repoRoot)
   301→	}
   302→
   303→	// Check if there are any changes
   304→	totalChanges := len(relModifiedFiles) + len(relNewFiles) + len(relDeletedFiles)
   305→	if totalChanges == 0 {
   306→		fmt.Fprintf(os.Stderr, "No files were modified during this session\n")
   307→		fmt.Fprintf(os.Stderr, "Skipping commit\n")
   308→		transitionSessionTurnEnd(sessionID)
   309→		if cleanupErr := CleanupPrePromptState(sessionID); cleanupErr != nil {
   310→			fmt.Fprintf(os.Stderr, "Warning: failed to cleanup pre-prompt state: %v\n", cleanupErr)
   311→		}
   312→		return nil
   313→	}
   314→
   315→	// Log file changes
   316→	logFileChanges(relModifiedFiles, relNewFiles, relDeletedFiles)
   317→
   318→	// Create context file
   319→	contextFile := filepath.Join(sessionDirAbs, paths.ContextFileName)
   320→	if err := createContextFile(contextFile, commitMessage, sessionID, allPrompts, summary); err != nil {
   321→		return fmt.Errorf("failed to create context file: %w", err)
   322→	}
   323→	fmt.Fprintf(os.Stderr, "Created context file: %s\n", sessionDir+"/"+paths.ContextFileName)
   324→
   325→	// Get git author
   326→	author, err := GetGitAuthor()
   327→	if err != nil {
   328→		return fmt.Errorf("failed to get git author: %w", err)
   329→	}
   330→
   331→	// Get strategy and agent type
   332→	strat := GetStrategy()
   333→	agentType := ag.Type()
   334→
   335→	// Get transcript position/identifier from pre-prompt state
   336→	var transcriptIdentifierAtStart string
   337→	var transcriptLinesAtStart int
   338→	if preState != nil {
   339→		transcriptIdentifierAtStart = preState.LastTranscriptIdentifier
   340→		transcriptLinesAtStart = preState.TranscriptOffset
   341→	}
   342→
   343→	// Calculate token usage - prefer SubagentAwareExtractor to include subagent tokens
   344→	var tokenUsage *agent.TokenUsage
   345→	if subagentExtractor, ok := ag.(agent.SubagentAwareExtractor); ok {
   346→		usage, tokenErr := subagentExtractor.CalculateTotalTokenUsage(transcriptRef, transcriptLinesAtStart, subagentsDir)
   347→		if tokenErr != nil {
   348→			fmt.Fprintf(os.Stderr, "Warning: failed to calculate token usage (with subagents): %v\n", tokenErr)
   349→		} else {
   350→			tokenUsage = usage
   351→		}
   352→	} else if calculator, ok := ag.(agent.TokenCalculator); ok {
   353→		// Fall back to basic token calculation (main transcript only)
   354→		usage, tokenErr := calculator.CalculateTokenUsage(transcriptRef, transcriptLinesAtStart)
   355→		if tokenErr != nil {
   356→			fmt.Fprintf(os.Stderr, "Warning: failed to calculate token usage: %v\n", tokenErr)
   357→		} else {
   358→			tokenUsage = usage
   359→		}
   360→	}
   361→
   362→	// Build fully-populated step context and delegate to strategy
   363→	ctx := strategy.StepContext{
   364→		SessionID:                sessionID,
   365→		ModifiedFiles:            relModifiedFiles,
   366→		NewFiles:                 relNewFiles,
   367→		DeletedFiles:             relDeletedFiles,
   368→		MetadataDir:              sessionDir,
   369→		MetadataDirAbs:           sessionDirAbs,
   370→		CommitMessage:            commitMessage,
   371→		TranscriptPath:           transcriptRef,
   372→		AuthorName:               author.Name,
   373→		AuthorEmail:              author.Email,
   374→		AgentType:                agentType,
   375→		StepTranscriptIdentifier: transcriptIdentifierAtStart,
   376→		StepTranscriptStart:      transcriptLinesAtStart,
   377→		TokenUsage:               tokenUsage,
   378→	}
   379→
   380→	if err := strat.SaveStep(ctx); err != nil {
   381→		return fmt.Errorf("failed to save step: %w", err)
   382→	}
   383→
   384→	// Update session state transcript position for auto-commit strategy
   385→	if strat.Name() == strategy.StrategyNameAutoCommit && newTranscriptPosition > 0 {
   386→		updateAutoCommitTranscriptPosition(sessionID, newTranscriptPosition)
   387→	}
   388→
   389→	// Transition session phase and cleanup
   390→	transitionSessionTurnEnd(sessionID)
   391→	if cleanupErr := CleanupPrePromptState(sessionID); cleanupErr != nil {
   392→		fmt.Fprintf(os.Stderr, "Warning: failed to cleanup pre-prompt state: %v\n", cleanupErr)
   393→	}
   394→
   395→	return nil
   396→}
   397→
   398→// handleLifecycleCompaction handles context compaction: saves current progress
   399→// but stays in ACTIVE phase (unlike TurnEnd which transitions to IDLE).
   400→// Also resets the transcript offset since the transcript may be truncated.
   401→func handleLifecycleCompaction(ag agent.Agent, event *agent.Event) error {
   402→	logCtx := logging.WithAgent(logging.WithComponent(context.Background(), "lifecycle"), ag.Name())
   403→	logging.Info(logCtx, "compaction",
   404→		slog.String("event", event.Type.String()),
   405→		slog.String("session_id", event.SessionID),
   406→	)
   407→
   408→	// Fire EventCompaction to trigger ActionCondenseIfFilesTouched (stays in ACTIVE)
   409→	sessionID := event.SessionID
   410→	sessionState, loadErr := strategy.LoadSessionState(sessionID)
   411→	if loadErr != nil {
   412→		fmt.Fprintf(os.Stderr, "Warning: failed to load session state for compaction: %v\n", loadErr)
   413→	}
   414→	if sessionState != nil {
   415→		if transErr := strategy.TransitionAndLog(sessionState, session.EventCompaction, session.TransitionContext{}, session.NoOpActionHandler{}); transErr != nil {
   416→			fmt.Fprintf(os.Stderr, "Warning: compaction transition failed: %v\n", transErr)
   417→		}
   418→
   419→		// Reset transcript offset since the transcript may be truncated/reorganized
   420→		sessionState.CheckpointTranscriptStart = 0
   421→
   422→		if saveErr := strategy.SaveSessionState(sessionState); saveErr != nil {
   423→			fmt.Fprintf(os.Stderr, "Warning: failed to save session state after compaction: %v\n", saveErr)
   424→		}
   425→	}
   426→
   427→	fmt.Fprintf(os.Stderr, "Context compaction: transcript offset reset\n")
   428→	return nil
   429→}
