   431→// handleLifecycleSessionEnd handles session end: marks the session as ended.
   432→func handleLifecycleSessionEnd(ag agent.Agent, event *agent.Event) error {
   433→	logCtx := logging.WithAgent(logging.WithComponent(context.Background(), "lifecycle"), ag.Name())
   434→	logging.Info(logCtx, "session-end",
   435→		slog.String("event", event.Type.String()),
   436→		slog.String("session_id", event.SessionID),
   437→	)
   438→
   439→	if event.SessionID == "" {
   440→		return nil // No session to update
   441→	}
   442→
   443→	if err := markSessionEnded(event.SessionID); err != nil {
   444→		fmt.Fprintf(os.Stderr, "Warning: failed to mark session ended: %v\n", err)
   445→	}
   446→	return nil
   447→}
