   449→// handleLifecycleSubagentStart handles subagent start: captures pre-task state.
   450→func handleLifecycleSubagentStart(ag agent.Agent, event *agent.Event) error {
   451→	logCtx := logging.WithAgent(logging.WithComponent(context.Background(), "lifecycle"), ag.Name())
   452→	logging.Info(logCtx, "subagent-start",
   453→		slog.String("event", event.Type.String()),
   454→		slog.String("session_id", event.SessionID),
   455→		slog.String("tool_use_id", event.ToolUseID),
   456→	)
   457→
   458→	// Log context
   459→	fmt.Fprintf(os.Stdout, "[entire] Subagent started\n")
   460→	fmt.Fprintf(os.Stdout, "  Session ID: %s\n", event.SessionID)
   461→	fmt.Fprintf(os.Stdout, "  Tool Use ID: %s\n", event.ToolUseID)
   462→	fmt.Fprintf(os.Stdout, "  Transcript: %s\n", event.SessionRef)
   463→
   464→	// Capture pre-task state
   465→	if err := CapturePreTaskState(event.ToolUseID); err != nil {
   466→		return fmt.Errorf("failed to capture pre-task state: %w", err)
   467→	}
   468→
   469→	return nil
   470→}
   471→
   472→// handleLifecycleSubagentEnd handles subagent end: detects changes, saves task checkpoint.
   473→func handleLifecycleSubagentEnd(ag agent.Agent, event *agent.Event) error {
   474→	logCtx := logging.WithAgent(logging.WithComponent(context.Background(), "lifecycle"), ag.Name())
   475→	logging.Info(logCtx, "subagent-end",
   476→		slog.String("event", event.Type.String()),
   477→		slog.String("session_id", event.SessionID),
   478→		slog.String("tool_use_id", event.ToolUseID),
   479→		slog.String("subagent_id", event.SubagentID),
   480→	)
   481→
   482→	// Extract subagent type and description from tool input
   483→	subagentType, taskDescription := ParseSubagentTypeAndDescription(event.ToolInput)
   484→
   485→	// Determine subagent transcript path
   486→	transcriptDir := filepath.Dir(event.SessionRef)
   487→	var subagentTranscriptPath string
   488→	if event.SubagentID != "" {
   489→		subagentTranscriptPath = AgentTranscriptPath(transcriptDir, event.SubagentID)
   490→		if !fileExists(subagentTranscriptPath) {
   491→			subagentTranscriptPath = ""
   492→		}
   493→	}
   494→
   495→	// Log context
   496→	fmt.Fprintf(os.Stdout, "[entire] Subagent completed\n")
   497→	fmt.Fprintf(os.Stdout, "  Session ID: %s\n", event.SessionID)
   498→	fmt.Fprintf(os.Stdout, "  Tool Use ID: %s\n", event.ToolUseID)
   499→	if event.SubagentID != "" {
   500→		fmt.Fprintf(os.Stdout, "  Agent ID: %s\n", event.SubagentID)
   501→	}
   502→	if subagentTranscriptPath != "" {
   503→		fmt.Fprintf(os.Stdout, "  Subagent Transcript: %s\n", subagentTranscriptPath)
   504→	}
   505→
   506→	// Extract modified files from subagent transcript
   507→	var modifiedFiles []string
   508→	if analyzer, ok := ag.(agent.TranscriptAnalyzer); ok {
   509→		transcriptToScan := event.SessionRef
   510→		if subagentTranscriptPath != "" {
   511→			transcriptToScan = subagentTranscriptPath
   512→		}
   513→		if files, _, fileErr := analyzer.ExtractModifiedFilesFromOffset(transcriptToScan, 0); fileErr != nil {
   514→			fmt.Fprintf(os.Stderr, "Warning: failed to extract modified files from subagent: %v\n", fileErr)
   515→		} else {
   516→			modifiedFiles = files
   517→		}
   518→	}
   519→
   520→	// Load pre-task state and detect file changes
   521→	preState, err := LoadPreTaskState(event.ToolUseID)
   522→	if err != nil {
   523→		fmt.Fprintf(os.Stderr, "Warning: failed to load pre-task state: %v\n", err)
   524→	}
   525→	changes, err := DetectFileChanges(preState.PreUntrackedFiles())
   526→	if err != nil {
   527→		fmt.Fprintf(os.Stderr, "Warning: failed to compute file changes: %v\n", err)
   528→	}
   529→
   530→	// Get repo root and normalize paths
   531→	repoRoot, err := paths.RepoRoot()
   532→	if err != nil {
   533→		return fmt.Errorf("failed to get repo root: %w", err)
   534→	}
   535→
   536→	relModifiedFiles := FilterAndNormalizePaths(modifiedFiles, repoRoot)
   537→	var relNewFiles, relDeletedFiles []string
   538→	if changes != nil {
   539→		relNewFiles = FilterAndNormalizePaths(changes.New, repoRoot)
   540→		relDeletedFiles = FilterAndNormalizePaths(changes.Deleted, repoRoot)
   541→	}
   542→
   543→	// If no changes, skip
   544→	if len(relModifiedFiles) == 0 && len(relNewFiles) == 0 && len(relDeletedFiles) == 0 {
   545→		fmt.Fprintf(os.Stderr, "[entire] No file changes detected, skipping task checkpoint\n")
   546→		_ = CleanupPreTaskState(event.ToolUseID) //nolint:errcheck // best-effort cleanup
   547→		return nil
   548→	}
   549→
   550→	// Find checkpoint UUID from main transcript (best-effort)
   551→	var checkpointUUID string
   552→	if analyzer, ok := ag.(agent.TranscriptAnalyzer); ok {
   553→		// Use ExtractModifiedFilesFromOffset on the main transcript to get position info
   554→		// and then look for checkpoint UUID via the legacy path
   555→		_ = analyzer // UUID lookup requires transcript parsing — delegate to existing helper
   556→	}
   557→	// Fall back to the existing CLI-level checkpoint UUID finder
   558→	mainLines, _, _ := parseTranscriptForCheckpointUUID(event.SessionRef) //nolint:errcheck // best-effort
   559→	if mainLines != nil {
   560→		checkpointUUID, _ = FindCheckpointUUID(mainLines, event.ToolUseID)
   561→	}
   562→
   563→	// Get git author
   564→	author, err := GetGitAuthor()
   565→	if err != nil {
   566→		return fmt.Errorf("failed to get git author: %w", err)
   567→	}
   568→
   569→	// Build task checkpoint context
   570→	strat := GetStrategy()
   571→	agentType := ag.Type()
   572→
   573→	ctx := strategy.TaskStepContext{
   574→		SessionID:              event.SessionID,
   575→		ToolUseID:              event.ToolUseID,
   576→		AgentID:                event.SubagentID,
   577→		ModifiedFiles:          relModifiedFiles,
   578→		NewFiles:               relNewFiles,
   579→		DeletedFiles:           relDeletedFiles,
   580→		TranscriptPath:         event.SessionRef,
   581→		SubagentTranscriptPath: subagentTranscriptPath,
   582→		CheckpointUUID:         checkpointUUID,
   583→		AuthorName:             author.Name,
   584→		AuthorEmail:            author.Email,
   585→		SubagentType:           subagentType,
   586→		TaskDescription:        taskDescription,
   587→		AgentType:              agentType,
   588→	}
   589→
   590→	if err := strat.SaveTaskStep(ctx); err != nil {
   591→		return fmt.Errorf("failed to save task step: %w", err)
   592→	}
   593→
   594→	_ = CleanupPreTaskState(event.ToolUseID) //nolint:errcheck // best-effort cleanup
   595→	return nil
   596→}
   597→
   598→// --- Helper functions ---
   599→
   600→// resolveTranscriptOffset determines the transcript offset to use for parsing.
   601→// Prefers pre-prompt state, falls back to session state.
   602→func resolveTranscriptOffset(preState *PrePromptState, sessionID string) int {
   603→	if preState != nil && preState.TranscriptOffset > 0 {
   604→		fmt.Fprintf(os.Stderr, "Pre-prompt state found: parsing transcript from offset %d\n", preState.TranscriptOffset)
   605→		return preState.TranscriptOffset
   606→	}
   607→
   608→	// Fall back to session state (e.g., auto-commit strategy updates it after each save)
   609→	sessionState, loadErr := strategy.LoadSessionState(sessionID)
   610→	if loadErr != nil {
   611→		fmt.Fprintf(os.Stderr, "Warning: failed to load session state: %v\n", loadErr)
   612→		return 0
   613→	}
   614→	if sessionState != nil && sessionState.CheckpointTranscriptStart > 0 {
   615→		fmt.Fprintf(os.Stderr, "Session state found: parsing transcript from offset %d\n", sessionState.CheckpointTranscriptStart)
   616→		return sessionState.CheckpointTranscriptStart
   617→	}
   618→
   619→	return 0
   620→}
   621→
   622→// updateAutoCommitTranscriptPosition updates the session state with the new transcript position
   623→// for the auto-commit strategy.
   624→func updateAutoCommitTranscriptPosition(sessionID string, newPosition int) {
   625→	sessionState, loadErr := strategy.LoadSessionState(sessionID)
   626→	if loadErr != nil {
   627→		fmt.Fprintf(os.Stderr, "Warning: failed to load session state: %v\n", loadErr)
   628→		return
   629→	}
   630→	if sessionState == nil {
   631→		sessionState = &strategy.SessionState{
   632→			SessionID: sessionID,
   633→		}
   634→	}
   635→	sessionState.CheckpointTranscriptStart = newPosition
   636→	sessionState.StepCount++
   637→	if updateErr := strategy.SaveSessionState(sessionState); updateErr != nil {
   638→		fmt.Fprintf(os.Stderr, "Warning: failed to update session state: %v\n", updateErr)
   639→	} else {
   640→		fmt.Fprintf(os.Stderr, "Updated session state: transcript position=%d, checkpoint=%d\n",
   641→			newPosition, sessionState.StepCount)
   642→	}
   643→}
   644→
   645→// createContextFile creates a context.md file for the session checkpoint.
   646→// This is a unified version that works for all agents.
   647→func createContextFile(contextFile, commitMessage, sessionID string, prompts []string, summary string) error {
   648→	var sb strings.Builder
   649→
   650→	sb.WriteString("# Session Context\n\n")
   651→	sb.WriteString(fmt.Sprintf("Session ID: %s\n", sessionID))
   652→	sb.WriteString(fmt.Sprintf("Commit Message: %s\n\n", commitMessage))
   653→
   654→	if len(prompts) > 0 {
   655→		sb.WriteString("## Prompts\n\n")
   656→		for i, p := range prompts {
   657→			sb.WriteString(fmt.Sprintf("### Prompt %d\n\n%s\n\n", i+1, p))
   658→		}
   659→	}
   660→
   661→	if summary != "" {
   662→		sb.WriteString("## Summary\n\n")
   663→		sb.WriteString(summary)
   664→		sb.WriteString("\n")
   665→	}
   666→
   667→	if err := os.WriteFile(contextFile, []byte(sb.String()), 0o600); err != nil {
   668→		return fmt.Errorf("failed to write context file: %w", err)
   669→	}
   670→	return nil
   671→}
   672→
   673→// parseTranscriptForCheckpointUUID is a thin wrapper around transcript parsing for checkpoint UUID lookup.
   674→// Returns parsed transcript lines for use with FindCheckpointUUID.
   675→func parseTranscriptForCheckpointUUID(transcriptPath string) ([]transcriptLine, int, error) {
   676→	lines, total, err := transcript.ParseFromFileAtLine(transcriptPath, 0)
   677→	if err != nil {
   678→		return nil, 0, fmt.Errorf("parsing transcript for checkpoint UUID: %w", err)
   679→	}
   680→	return lines, total, nil
   681→}
   682→
   683→// transitionSessionTurnEnd transitions the session phase to IDLE and dispatches turn-end actions.
   684→func transitionSessionTurnEnd(sessionID string) {
   685→	turnState, loadErr := strategy.LoadSessionState(sessionID)
   686→	if loadErr != nil {
   687→		fmt.Fprintf(os.Stderr, "Warning: failed to load session state for turn end: %v\n", loadErr)
   688→		return
   689→	}
   690→	if turnState == nil {
   691→		return
   692→	}
   693→	if err := strategy.TransitionAndLog(turnState, session.EventTurnEnd, session.TransitionContext{}, session.NoOpActionHandler{}); err != nil {
   694→		fmt.Fprintf(os.Stderr, "Warning: turn-end transition failed: %v\n", err)
   695→	}
   696→
   697→	// Always dispatch to strategy for turn-end handling. The strategy reads
   698→	// work items from state (e.g. TurnCheckpointIDs), not the action list.
   699→	strat := GetStrategy()
   700→	if handler, ok := strat.(strategy.TurnEndHandler); ok {
   701→		if err := handler.HandleTurnEnd(turnState); err != nil {
   702→			fmt.Fprintf(os.Stderr, "Warning: turn-end action dispatch failed: %v\n", err)
   703→		}
   704→	}
   705→
   706→	if updateErr := strategy.SaveSessionState(turnState); updateErr != nil {
   707→		fmt.Fprintf(os.Stderr, "Warning: failed to update session phase on turn end: %v\n", updateErr)
   708→	}
   709→}
   710→
   711→// markSessionEnded transitions the session to ENDED phase via the state machine.
   712→func markSessionEnded(sessionID string) error {
   713→	state, err := strategy.LoadSessionState(sessionID)
   714→	if err != nil {
   715→		return fmt.Errorf("failed to load session state: %w", err)
   716→	}
   717→	if state == nil {
   718→		return nil // No state file, nothing to update
   719→	}
   720→
   721→	if transErr := strategy.TransitionAndLog(state, session.EventSessionStop, session.TransitionContext{}, session.NoOpActionHandler{}); transErr != nil {
   722→		fmt.Fprintf(os.Stderr, "Warning: session stop transition failed: %v\n", transErr)
   723→	}
   724→
   725→	now := time.Now()
   726→	state.EndedAt = &now
   727→
   728→	if err := strategy.SaveSessionState(state); err != nil {
   729→		return fmt.Errorf("failed to save session state: %w", err)
   730→	}
   731→	return nil
   732→}
   733→
   734→// logFileChanges logs the files modified, created, and deleted during a session.
   735→func logFileChanges(modified, newFiles, deleted []string) {
   736→	fmt.Fprintf(os.Stderr, "Files modified during session (%d):\n", len(modified))
   737→	for _, file := range modified {
   738→		fmt.Fprintf(os.Stderr, "  - %s\n", file)
   739→	}
   740→	if len(newFiles) > 0 {
   741→		fmt.Fprintf(os.Stderr, "New files created (%d):\n", len(newFiles))
   742→		for _, file := range newFiles {
   743→			fmt.Fprintf(os.Stderr, "  - %s\n", file)
   744→		}
   745→	}
   746→	if len(deleted) > 0 {
   747→		fmt.Fprintf(os.Stderr, "Files deleted (%d):\n", len(deleted))
   748→		for _, file := range deleted {
   749→			fmt.Fprintf(os.Stderr, "  - %s\n", file)
   750→		}
   751→	}
   752→}
   753→

